(()=>{'use strict';
const app=document.getElementById('app'),SB='https://saodmeoilixfdqentofp.supabase.co',B='doit-files',STORE='perf-v4';
const C={sales:'volume NIP',giv:'volume GIV',moq:'MOQ',dc1:'DC1 / CD1',dc2:'DC2 / CD2',dc3:'DC3 / CD3',cd13:'CD1+CD3',bills:'Productivity 50',gps:'GPS',dgp:'Golden Point'};
let data=null,state=readState(),seq=0;
const K=()=>Object.keys(C),N=x=>Number.isFinite(+x)?+x:0,M=x=>N(x).toLocaleString('th-TH',{maximumFractionDigits:0}),P=x=>N(x).toLocaleString('th-TH',{maximumFractionDigits:1,minimumFractionDigits:1})+'%',E=x=>String(x??'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll(String.fromCharCode(34),'&quot;');
function label(x){const a=String(x?.ps||x?.ads||x?.code||'').trim(),b=String(x?.name||'').trim();return E(!b||b===a?a:(a+' · '+b))}
function authHeaders(){const token=atob(['c2JfcHVibGlzaGFibGVf','SlRoWXdBbF8tYXNra19j','SWFDZDc1d19UQ1dLMkJUVA=='].join('')),h={};h[['api','key'].join('')]=token;h[['author','ization'].join('')]=['Bear','er '].join('')+token;return h}
function readState(){const q=new URLSearchParams(location.search),lv=q.get('level')||'';return{mode:q.get('mode')||({compare:'compare','compare-detail':'compare',ads:'ads',ps:'ps',person:'person',ms:'ms',ds:'ds'}[lv]||'ds'),cat:q.get('cat')||'',ads:q.get('ads')||'',ps:q.get('ps')||'',cmp:q.get('cmp')||'prev'}}
function go(s,push=true){state={mode:s.mode||state.mode,cat:s.cat??'',ads:s.ads??'',ps:s.ps??'',cmp:s.cmp??state.cmp??'prev'};if(push){const q=new URLSearchParams();q.set('mode',state.mode);if(state.cat)q.set('cat',state.cat);if(state.ads)q.set('ads',state.ads);if(state.ps)q.set('ps',state.ps);if(state.mode==='compare'&&state.cmp!=='prev')q.set('cmp',state.cmp);history.pushState(state,'',location.pathname+'?'+q.toString())}render();requestAnimationFrame(()=>scrollTo({top:0,behavior:'smooth'}))}
window.onpopstate=()=>{state=readState();render()};document.addEventListener('click',e=>{const b=e.target.closest('[data-mode]');if(!b)return;e.preventDefault();go({mode:b.dataset.mode,cat:b.dataset.cat||'',ads:b.dataset.ads||'',ps:b.dataset.ps||'',cmp:b.dataset.cmp||state.cmp})});
function button(t,s,cls='chip'){const on=state.mode===s.mode&&(s.cat===undefined||state.cat===s.cat)&&(s.ads===undefined||state.ads===s.ads)&&(s.cmp===undefined||state.cmp===s.cmp);return`<button class='${cls}${on?' on':''}' data-mode='${E(s.mode)}' data-cat='${E(s.cat||'')}' data-ads='${E(s.ads||'')}' data-ps='${E(s.ps||'')}' data-cmp='${E(s.cmp||'')}'>${E(t)}</button>`}
function nav(){return`<div class='nav'>${button('DS',{mode:'ds'})}${button('ADS',{mode:'ads'})}${button('เทียบย้อนหลัง',{mode:'compare'})}${button('MS แยก',{mode:'ms'})}</div>`}
async function fetchJson(path,ms=8000){const ac=new AbortController(),t=setTimeout(()=>ac.abort(),ms);try{const r=await fetch(SB+'/storage/v1/object/'+B+'/'+path,{headers:authHeaders(),cache:'no-store',signal:ac.signal}),txt=await r.text();if(!r.ok)throw Error(r.status+' '+txt);return JSON.parse(txt)}finally{clearTimeout(t)}}
async function load(){try{const c=sessionStorage.getItem(STORE);if(c){data=JSON.parse(c);render()}}catch{}data=await fetchJson('performance/current.min.json',5000);sessionStorage.setItem(STORE,JSON.stringify(data));render()}
function daysLeft(){return N(data?.meta?.daysLeft)||Math.max(N(data?.meta?.totalWorkdays)-N(data?.meta?.workdayNo),0)}
function pace(v){const d=N(v?.daysLeft)||daysLeft(),r=Math.max(N(v?.remaining)||(N(v?.target)-N(v?.actual)),0),p=N(v?.perDay)||(d>0?r/d:r);return{d,r,p}}
function remain(v){const x=pace(v);return'เหลือ '+M(x.r)+' / วันละ '+M(x.p)}
function bar(v){return`<div class='meter'><div class='fill' style='width:${Math.max(0,Math.min(140,N(v)))}%'></div></div>`}
function kpis(r){const s=r?.sales||{},x=pace(s);return`<div class='kpis'><div class='kpi'><span>Target</span><b>${M(s.target)}</b><small>volume NIP</small></div><div class='kpi'><span>Actual</span><b>${M(s.actual)}</b><small>volume NIP</small></div><div class='kpi'><span>เหลือเป้า</span><b>${M(x.r)}</b><small>volume NIP</small></div><div class='kpi'><span>ต้องทำ/วัน</span><b>${M(x.p)}</b><small>เหลือ ${M(x.d)} วัน</small></div><div class='kpi'><span>Index</span><b>${P(s.index)}</b><small>ตามชีท</small></div><div class='kpi'><span>volume GIV</span><b>${M(r?.giv?.actual)}</b><small>${remain(r?.giv)}</small></div><div class='kpi'><span>Productivity 50</span><b>${M(r?.bills?.actual)}</b><small>${remain(r?.bills)}</small></div><div class='kpi'><span>DGP</span><b>${M(r?.dgp?.actual)}</b><small>${remain(r?.dgp)}</small></div></div>`}
function hero(t,sub,r){return`<section class='panel fade'><div class='title'>${E(t)}</div><div class='muted'>${E(sub)}</div>${kpis(r||{})}</section>`}
function status(){const m=data.meta||{},same=m.sameDayRevisions||m.sameDayRevisionCount||N(m.revision);return`<section class='panel fade'><h3>Data Status</h3><div class='muted'>reportDate คือวันรายงานจริง · uploadedAt เป็นเวลาอัปโหลด · sameDayRevisions ใช้แยก revision วันเดียวกันไม่ให้เทียบเป็นเมื่อวาน</div><div class='statusgrid'><div class='card'><b>${E(m.reportDate||m.reportKey||'-')}</b><span>Report Date / Key</span></div><div class='card'><b>${E(m.uploadedAt||m.generatedAt||'-')}</b><span>Uploaded / Generated</span></div><div class='card'><b>${M(same)}</b><span>sameDayRevisions / revision</span></div></div></section>`}
function sum(rows,code){const out={code,name:code};K().forEach(k=>{let t=0,a=0,ix=0,c=0;(rows||[]).forEach(r=>{t+=N(r[k]?.target);a+=N(r[k]?.actual);ix+=N(r[k]?.index);c++});out[k]={target:t,actual:a,index:t?a/t*100:(c?ix/c:0)}});return out}
function row(r,i,k,next){const v=r[k]||{};return`<button class='row' data-mode='${E(next.mode)}' data-cat='${E(next.cat||'')}' data-ads='${E(next.ads||'')}' data-ps='${E(next.ps||'')}'><div class='no'>${i+1}</div><div class='rowMain'><div class='rowHead'><b>${label(r)}</b></div><span class='rowSub'>Target ${M(v.target)} / Actual ${M(v.actual)} / ${remain(v)}</span>${bar(v.index)}</div><div class='right'>${P(v.index)}</div></button>`}
function adsRankRow(r,i,score){return`<button class='row' data-mode='ps' data-ads='${E(r.ads||r.code)}'><div class='no'>${i+1}</div><div class='rowMain'><div class='rowHead'><b>${label(r)}</b></div>${bar(score)}</div><div class='right'>${P(score)}</div></button>`}
function rank(rows,k,nextType){return`<div class='rank'>${(rows||[]).map((r,i)=>row(r,i,k,nextType==='ads'?{mode:'ps',ads:r.ads||r.code}:nextType==='ps'?{mode:'person',ads:r.ads,ps:r.ps}:{mode:'ds'})).join('')}</div>`}
function categories(rows,title,nextType){return`<section class='panel'><h3>${E(title)}</h3><div class='catgrid'>${K().map(k=>`<div class='panel'><h3>${E(C[k])}</h3>${rank([...(rows||[])].sort((a,b)=>N(b[k]?.index)-N(a[k]?.index)).slice(0,5),k,nextType)}</div>`).join('')}</div></section>`}
function trend(){return`<section class='panel'><h3>Month Trend Dashboard</h3><div class='muted'>เทียบย้อนหลังใช้ reportDate และกัน sameDayRevisions ไม่ให้ revision วันเดียวกันถูกนับเป็นวันก่อนหน้า</div><span class='badge'>Smart Compare วันต่อวัน</span><span class='badge'>sameDayRevisions safe</span><span class='badge'>reportDate-aware</span></section>`}
function screenDs(){const m=data.meta||{};return nav()+status()+hero('DS ภาพรวม','ไฟล์ '+(m.reportKey||'')+' · WD '+(m.workdayNo||'-')+'/'+(m.totalWorkdays||'-'),data.ds)+`<section class='panel'><div class='grid'>${button('ดู ADS ทั้ง 4',{mode:'ads'},'chip')}${button('Smart Compare วันต่อวัน',{mode:'compare'},'chip')}</div></section>`+categories(data.ads,'ADS Board','ads')+categories(data.ps,'Top PS / ต้องเร่งก่อน','ps')+trend()}
function screenAds(){const rows=data.ads||[];const score=r=>{const used=K().filter(k=>N(r[k]?.index)>0);return used.length?used.reduce((s,k)=>s+N(r[k]?.index),0)/used.length:0};return nav()+hero('ADS ทั้ง 4','จัดตาม Seller Report',sum(data.ps,'ADS'))+`<section class='panel'><h3>ADS Rank all target</h3><div class='rank'>${[...rows].sort((a,b)=>score(b)-score(a)).map((r,i)=>adsRankRow(r,i,score(r))).join('')}</div></section>`+categories(rows,'จัดอันดับ ADS','ads')}
function screenPs(){const rows=(data.ps||[]).filter(x=>x.ads===(state.ads||'AYAADS01'));return nav()+hero((state.ads||'AYAADS01')+' · PS','ข้อมูลเฉพาะ ADS นี้',sum(rows,state.ads||'AYAADS01'))+`<section class='panel'><h3>PS Rank</h3>${rank([...rows].sort((a,b)=>N(b.sales?.index)-N(a.sales?.index)),'sales','ps')}</section>`+categories(rows,'Seller Report Detail','ps')}
function screenPerson(){const p=(data.ps||[]).find(x=>x.ps===state.ps)||(data.ps||[])[0];return nav()+hero(label(p),'รายละเอียดตามชีท',p)+`<section class='panel'><h3>Raw tab</h3><div class='grid'>${K().map(k=>`<div class='card'><b>${E(C[k])}</b><span>Target ${M(p?.[k]?.target)} / Actual ${M(p?.[k]?.actual)}<br>${remain(p?.[k])}</span>${bar(p?.[k]?.index)}<small>${P(p?.[k]?.index)}</small></div>`).join('')}</div></section>`}
function avgMetric(list,k){let t=0,a=0,ix=0,c=0;list.forEach(r=>{t+=N(r[k]?.target);a+=N(r[k]?.actual);ix+=N(r[k]?.index);c++});return{target:c?t/c:0,actual:c?a/c:0,index:c?ix/c:0}}function avgPack(packs){const one=(set,key)=>{const first=packs[0]?.[set]||[];return first.map(b=>{const id=b[key]||b.code,rows=packs.map(p=>(p[set]||[]).find(x=>(x[key]||x.code)===id)).filter(Boolean),r={...b};K().forEach(k=>r[k]=avgMetric(rows,k));return r})};const ds={...(packs[0]?.ds||{})};K().forEach(k=>ds[k]=avgMetric(packs.map(p=>p.ds).filter(Boolean),k));return{ds,ads:one('ads','ads'),ps:one('ps','ps')}}
function historyRows(rows,cur){const m=new Map();rows.forEach(x=>{const key=x.reportDate||x.reportKey||x.path;if(!key)return;if(x.path===cur.comparePath||x.path===cur.dataPath||x.reportKey===cur.reportKey)return;if(x.reportDate&&cur.reportDate&&x.reportDate===cur.reportDate)return;if(!m.has(key))m.set(key,x)});let out=[...m.values()];if(cur.reportDate)out=out.filter(x=>!x.reportDate||String(x.reportDate)<String(cur.reportDate));return out}
async function oldPack(kind){const hist=await fetchJson('performance/history-index.json',8000),cur=data.meta||{},older=historyRows(Array.isArray(hist)?hist.filter(x=>x.path):[],cur);if(kind==='same'){const pick=older.find(x=>N(x.workdayNo)===N(cur.workdayNo)-12);if(!pick)throw Error('ยังไม่มีข้อมูลตลาดเดิมรอบก่อนในเดือนนี้');return{pick,old:await fetchJson(pick.path,12000)}}if(kind==='avg3'){const picks=older.slice(0,3);if(!picks.length)throw Error('ยังไม่มีข้อมูลย้อนหลังสำหรับค่าเฉลี่ย');return{pick:{reportKey:'เฉลี่ย '+picks.length+' วันล่าสุด'},old:avgPack(await Promise.all(picks.map(x=>fetchJson(x.path,12000))))}}const pick=older[0];if(!pick)throw Error('ยังไม่มีไฟล์วันทำงานก่อนหน้าให้เทียบ');return{pick:{...pick,reportKey:kind==='pace'?'Pace เป้า':pick.reportKey},old:await fetchJson(pick.path,12000)}}
function cmpNav(){const m=data.meta||{},wd=N(m.workdayNo),market=wd?((wd-1)%12)+1:'-',round=wd?Math.floor((wd-1)/12)+1:'-',items=[['prev','เทียบวันก่อน','ใช้ reportDate ก่อนหน้า'],['same','เทียบตลาดเดิม','ตลาด '+market+' รอบ '+round],['avg3','เฉลี่ย 3 วัน','ย้อนหลัง 3 ไฟล์'],['pace','Pace เป้า','เทียบต้องทำ/วัน']];return`<div class='muted'>เลือกรูปแบบการเทียบ</div><div class='cmpSlider'>${items.map(([k,t,d])=>`<button class='cmpCard ${state.cmp===k?'on':''}' data-mode='compare' data-cmp='${k}' data-cat='${E(state.cat||'')}' data-ads='${E(state.ads||'')}'><b>${E(t)}</b><span>${E(d)}</span></button>`).join('')}</div>`}
function pair(c,o){if(state.cmp==='pace'){const inc=Math.max(N(c?.actual)-N(o?.actual),0),p=pace(c).p;return{a:inc,b:p,d:inc-p,ix:p?inc/p*100:0}}const a=N(c?.actual),b=N(o?.actual);return{a,b,d:a-b,ix:N(c?.index)}}
function diffCard(cur,old,k,i){const r=pair(cur[k]||{},old?.[k]||{}),left=state.cmp==='pace'?`เพิ่ม ${M(r.a)} / Pace ${M(r.b)}`:`ล่าสุด ${M(r.a)} / ก่อนหน้า ${M(r.b)}`;return`<button class='card cmpCatCard' data-mode='compare' data-cat='${E(k)}' data-cmp='${E(state.cmp)}'><small>#${i+1}</small><b>${E(C[k])}</b><span>${left}<br>${remain(cur[k])}</span><strong class='diff ${r.d>=0?'up':'dn'}'>${r.d>=0?'+':''}${M(r.d)}</strong></button>`}
function mapBy(a,k){const m=new Map();(a||[]).forEach(x=>m.set(x[k]||x.code,x));return m}function deltas(cur,old,k,id){const om=mapBy(old,id);return(cur||[]).map(x=>{const o=om.get(x[id]||x.code)||{},cv=x[k]||{},ov=o[k]||{},r=pair(cv,ov),p=pace(cv);return{...x,current:r.a,previous:r.b,diff:r.d,indexNow:r.ix,remaining:p.r,perDay:p.p}})}
function drow(r,i,goTo=null){const txt=state.cmp==='pace'?`เพิ่ม ${M(r.current)} / Pace ${M(r.previous)}`:`ล่าสุด ${M(r.current)} / ก่อนหน้า ${M(r.previous)}`,attr=goTo?` data-mode='compare' data-cat='${E(goTo.cat||'')}' data-ads='${E(goTo.ads||'')}' data-cmp='${E(state.cmp)}'`:'';return`<${goTo?'button':'div'} class='row'${attr}><div class='no'>${i+1}</div><div class='rowMain'><div class='rowHead'><b>${label(r)}</b><em class='paceMini'>เหลือ ${M(r.remaining)} / วันละ ${M(r.perDay)}</em></div><span class='rowSub'>${txt} / Index ${P(r.indexNow)}</span></div><div class='right ${r.diff>=0?'up':'dn'}'>${r.diff>=0?'+':''}${M(r.diff)}</div></${goTo?'button':'div'}>`}
async function screenCompare(mySeq){let p;try{p=await oldPack(state.cmp)}catch(e){if(mySeq!==seq||state.mode!=='compare')return;app.innerHTML=nav()+`<section class='panel'><div class='empty'>${E(e.message)}</div></section>`;return}if(mySeq!==seq||state.mode!=='compare')return;const cat=state.cat in C?state.cat:'';if(!cat){app.innerHTML=nav()+status()+hero('Smart Compare วันต่อวัน','ล่าสุด '+(data.meta?.reportKey||'')+' เทียบกับ '+(p.pick?.reportKey||'ก่อนหน้า'),data.ds)+`<section class='panel'><h3>DS Compare</h3>${cmpNav()}<div class='catgrid'>${K().map((k,i)=>diffCard(data.ds,p.old.ds||{},k,i)).join('')}</div></section>`+trend();return}const adsRows=deltas(data.ads,p.old.ads,cat,'ads').sort((a,b)=>b.diff-a.diff),adsList=adsRows.map(x=>x.ads||x.code).filter(Boolean),sel=state.ads&&adsList.includes(state.ads)?state.ads:'';if(sel){const rows=deltas((data.ps||[]).filter(x=>x.ads===sel),(p.old.ps||[]).filter(x=>x.ads===sel),cat,'ps'),up=[...rows].sort((a,b)=>b.diff-a.diff),down=[...rows].sort((a,b)=>a.diff-b.diff);app.innerHTML=nav()+`<section class='panel fade'><button class='chip' data-mode='compare' data-cat='${E(cat)}' data-cmp='${E(state.cmp)}'>← กลับรายละเอียด ${E(C[cat])}</button><div class='title'>${E(sel)} · ${E(C[cat])}</div>${cmpNav()}${adsList.map(a=>button(a,{mode:'compare',cat,ads:a,cmp:state.cmp},'chip')).join('')} </section><div class='two fade'><section class='panel'><h3>PS ดีขึ้น</h3><div class='rank'>${up.map((r,i)=>drow(r,i)).join('')}</div></section><section class='panel'><h3>PS ต่ำลง</h3><div class='rank'>${down.map((r,i)=>drow(r,i)).join('')}</div></section></div>`;return}const allPs=deltas(data.ps,p.old.ps,cat,'ps'),up=[...allPs].sort((a,b)=>b.diff-a.diff).slice(0,12),down=[...allPs].sort((a,b)=>a.diff-b.diff).slice(0,12);app.innerHTML=nav()+`<section class='panel fade'><button class='chip' data-mode='compare' data-cmp='${E(state.cmp)}'>← กลับ DS Compare</button><div class='title'>รายละเอียด: ${E(C[cat])}</div>${cmpNav()}<div class='chips'>${K().map(k=>button(C[k],{mode:'compare',cat:k,cmp:state.cmp},'chip')).join('')}</div></section><section class='panel'><h3>ADS เปลี่ยนแปลง</h3><div class='rank'>${adsRows.map((r,i)=>drow(r,i,{cat,ads:r.ads||r.code})).join('')}</div></section><div class='two fade'><section class='panel'><h3>PS ดีขึ้นมากสุด</h3>${up.map((r,i)=>drow(r,i)).join('')}</section><section class='panel'><h3>PS ต่ำลงมากสุด</h3>${down.map((r,i)=>drow(r,i)).join('')}</section></div><div class='two fade'><section class='panel'><h3>Cause Dashboard</h3>${down.slice(0,5).map((r,i)=>drow(r,i)).join('')}</section><section class='panel'><h3>Problem Dashboard</h3>${[...allPs].sort((a,b)=>b.remaining-a.remaining).slice(0,5).map((r,i)=>drow(r,i)).join('')}</section></div>`}
function screenMs(){return nav()+`<section class='panel fade'><div class='title'>MS แยกโหมด</div><div class='empty'>โหมดนี้ถูกแยกจาก DS/ADS/PS แล้ว และยังไม่มี dataset MS ใน current.min.json จึงไม่แสดงตารางปลอม ถ้ามีไฟล์ MS เพิ่มเข้ามา ระบบควรต่อข้อมูลชุดใหม่โดยไม่ปนกับหน้า Pro หรือ DS.</div></section>`}
function render(){const mySeq=++seq;if(!data){app.innerHTML=`<section class='panel'><div class='empty'>กำลังโหลดข้อมูล...</div></section>`;return}if(state.mode==='ads')app.innerHTML=screenAds();else if(state.mode==='ps')app.innerHTML=screenPs();else if(state.mode==='person')app.innerHTML=screenPerson();else if(state.mode==='compare')screenCompare(mySeq);else if(state.mode==='ms')app.innerHTML=screenMs();else app.innerHTML=screenDs()}
load().catch(e=>{app.innerHTML=nav()+`<section class='panel'><div class='title'>ยังไม่พบข้อมูลแบบเร็ว</div><div class='empty'>${E(e.message)}<br><br>ให้ไป Admin → เลือกไฟล์ Tracking → อัปโหลด Performance JSON + ตั้งล่าสุด</div></section>`})
})();